// Validate incoming requisition data
// Accepts item_id (preferred) or item_name for inventory lookup
const req = $input.first().json.body || $input.first().json;

const requiredBase = ['department', 'quantity_requested', 'requester'];
const missing = requiredBase.filter(field => !req[field]);
if (!req.item_id && !req.item_name) missing.push('item_id or item_name');

if (missing.length > 0) {
  return [{ json: { error: 'Missing required fields: ' + missing.join(', '), received: req } }];
}

const qty = parseFloat(req.quantity_requested);
if (isNaN(qty) || qty <= 0) {
  return [{ json: { error: 'Quantity must be a positive number', received: req.quantity_requested } }];
}

const reqId = 'REQ-' + new Date().getFullYear() + '-' + String(Date.now()).slice(-4);

return [{
  json: {
    requisition_id: reqId,
    department: req.department,
    item_id: req.item_id || null,
    item_name: req.item_name || null,
    quantity_requested: qty,
    unit: req.unit || 'each',
    urgency: req.urgency || 'routine',
    requester: req.requester,
    justification: req.justification || req.notes || '',
    submitted_at: new Date().toISOString()
  }
}];

// Merge all lookups into a single enriched requisition payload.
// Computes total_amount, approval_tier, and collects enrichment errors.
const reqData = $('Validate Input').first().json;
const invResp = $('Lookup Inventory Item').first().json;
const vendorResp = $('Lookup Vendor').first().json;
const contractResp = $('Lookup Contract Price').first().json;
const glResp = $('Lookup GL Code').first().json;

const firstFields = (resp) => (resp && resp.records && resp.records[0]) ? resp.records[0].fields : null;
const invRec = firstFields(invResp);
const vendorRec = firstFields(vendorResp);
const contractRec = firstFields(contractResp);
const glRec = firstFields(glResp);

const errors = [];
if (!invRec) {
  errors.push("Artikal nije pronadjen u Inventory (item_id=" + (reqData.item_id || 'null') + ", item_name=" + (reqData.item_name || 'null') + ")");
}
if (invRec && !vendorRec) {
  errors.push("Preferirani dobavljac nije pronadjen (preferred_vendor_id=" + (invRec.preferred_vendor_id || 'null') + ")");
}
if (invRec && !glRec) {
  errors.push("GL mapping nije pronadjen (department=" + reqData.department + ", category=" + (invRec.category || 'null') + ")");
}

// Price cascade: contracted > inventory unit_cost > 0 (hard error)
let unit_cost = 0;
let price_source = 'none';
if (contractRec && contractRec.contracted_price != null) {
  unit_cost = Number(contractRec.contracted_price);
  price_source = 'contract';
} else if (invRec && invRec.unit_cost != null) {
  unit_cost = Number(invRec.unit_cost);
  price_source = 'inventory';
}
if (unit_cost <= 0 && invRec) {
  errors.push("Nema cijene: ni ugovorena cijena ni inventory.unit_cost nisu dostupni");
}

const total_amount = Math.round(unit_cost * reqData.quantity_requested * 100) / 100;

// Approval tier per project spec (EUR)
let approval_tier;
if (total_amount < 500) approval_tier = 'auto';
else if (total_amount < 2000) approval_tier = 'dept_head';
else if (total_amount < 5000) approval_tier = 'zoran';
else approval_tier = 'zoran_gm';

const current_stock = invRec && invRec.current_stock != null ? Number(invRec.current_stock) : null;

const enriched = {
  // Identity
  requisition_id: reqData.requisition_id,
  submitted_at: reqData.submitted_at,
  status: errors.length > 0 ? 'enrichment_failed' : 'pending_validation',
  enrichment_error: errors.length > 0 ? errors.join('; ') : '',

  // Request
  department: reqData.department,
  requester: reqData.requester,
  urgency: reqData.urgency,
  justification: reqData.justification,
  quantity_requested: reqData.quantity_requested,
  unit: reqData.unit,

  // Item (resolved)
  item_id: invRec ? invRec.item_id : (reqData.item_id || null),
  item_name: invRec ? invRec.item_name : (reqData.item_name || null),
  category: invRec ? invRec.category : null,
  warehouse: invRec ? invRec.warehouse : null,
  current_stock,
  par_level: invRec && invRec.par_level != null ? Number(invRec.par_level) : null,
  reorder_point: invRec && invRec.reorder_point != null ? Number(invRec.reorder_point) : null,
  negative_stock: current_stock != null && current_stock < 0,

  // Vendor (resolved)
  vendor_id: vendorRec ? vendorRec.vendor_id : null,
  vendor_name: vendorRec ? vendorRec.vendor_name : 'TBD',
  vendor_email: vendorRec ? (vendorRec.contact_email || '') : '',
  vendor_payment_terms: vendorRec ? (vendorRec.payment_terms || null) : null,
  vendor_approved_status: vendorRec ? (vendorRec.approved_status || null) : null,

  // Pricing
  unit_cost,
  contracted_price: contractRec && contractRec.contracted_price != null ? Number(contractRec.contracted_price) : null,
  price_source,
  total_amount,

  // GL + approval
  gl_code: glRec ? (glRec.gl_account_code || null) : null,
  gl_name: glRec ? (glRec.gl_account_name || null) : null,
  budget_monthly: glRec && glRec.budget_monthly != null ? Number(glRec.budget_monthly) : null,
  approval_tier
};

// Airtable write body (use Code-node pattern per project conventions)
const airtable_body = {
  records: [{
    fields: {
      requisition_id: enriched.requisition_id,
      department: enriched.department,
      item_id: enriched.item_id,
      item_name: enriched.item_name,
      category: enriched.category,
      warehouse: enriched.warehouse,
      quantity_requested: enriched.quantity_requested,
      unit: enriched.unit,
      urgency: enriched.urgency,
      requester: enriched.requester,
      justification: enriched.justification,
      status: enriched.status,
      submitted_at: enriched.submitted_at,
      current_stock: enriched.current_stock,
      par_level: enriched.par_level,
      negative_stock: enriched.negative_stock,
      vendor_id: enriched.vendor_id,
      vendor_name: enriched.vendor_name,
      vendor_email: enriched.vendor_email,
      unit_cost: enriched.unit_cost,
      contracted_price: enriched.contracted_price,
      price_source: enriched.price_source,
      total_amount: enriched.total_amount,
      gl_code: enriched.gl_code,
      approval_tier: enriched.approval_tier,
      enrichment_error: enriched.enrichment_error
    }
  }]
};

return [{ json: { ...enriched, airtable_body } }];
